import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const TimbangGudang = () => {
  const navigate = useNavigate();

  const [rfid, setRfid] = useState(null);
  const [truck, setTruck] = useState(null);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  const [mode, setMode] = useState("TARA_GUDANG");

  const [form, setForm] = useState({
    tara_gudang: "",
    bruto_gudang: "",
  });

  const [list, setList] = useState([]);

  // ================= RFID =================
  const fetchRFID = useCallback(async () => {
    try {
      setLoading(true);

      const res = await axios.get("http://localhost:5000/api/rfid/latest");

      if (res.data.truck) {
        const t = res.data.truck;

        setRfid(t.truckId);
        setTruck(t);

        await syncStatus(t.truckId);
        await fetchData(t.truckId);
      } else {
        setTruck(null);
        setRfid(null);
      }
    } catch (err) {
      console.error("RFID ERROR:", err);
    } finally {
      setLoading(false);
    }
  }, []);

  // polling RFID
  useEffect(() => {
    const interval = setInterval(() => {
      if (!rfid) fetchRFID();
    }, 2000);

    return () => clearInterval(interval);
  }, [rfid, fetchRFID]);

  // ================= SYNC STATUS =================
  const syncStatus = async (truckId) => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/gudang/status/${truckId}`
      );

      if (res.data.step === "TARA_GUDANG") {
        setMode("TARA_GUDANG");
      } else if (res.data.step === "BRUTO_GUDANG") {
        setMode("BRUTO_GUDANG");
      } else {
        setMode("TARA_GUDANG");
      }
    } catch (err) {
      console.error("SYNC ERROR:", err);
      setMode("TARA_GUDANG");
    }
  };

  // ================= FETCH DATA =================
  const fetchData = async (truckId) => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/gudang/${truckId}`
      );
      setList(res.data || []);
    } catch (err) {
      console.error("FETCH ERROR:", err);
    }
  };

  // ================= HANDLE INPUT =================
  const handleChange = (e) => {
    setForm((p) => ({
      ...p,
      [e.target.name]: e.target.value,
    }));
  };

  // ================= SUBMIT =================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const truckId = truck?.truckId;
    if (!truckId) return alert("RFID belum terbaca");

    try {
      setSubmitting(true);

      // ================= TARA GUDANG =================
      if (mode === "TARA_GUDANG") {
        if (!form.tara_gudang) {
          return alert("Tara gudang wajib diisi");
        }

        await axios.put(
          `http://localhost:5000/api/gudang/tara/${truckId}`,
          {
            tara_gudang: Number(form.tara_gudang),
          }
        );

        alert("Tara gudang berhasil disimpan");

        setForm({ tara_gudang: "", bruto_gudang: "" });

        await syncStatus(truckId);
        await fetchData(truckId);
      }

      // ================= BRUTO GUDANG =================
      else {
        if (!form.bruto_gudang) {
          return alert("Bruto gudang wajib diisi");
        }

        await axios.put(
          `http://localhost:5000/api/gudang/bruto/${truckId}`,
          {
            bruto_gudang: Number(form.bruto_gudang),
          }
        );

        alert("Bruto gudang selesai (SELESAI)");

        setForm({ tara_gudang: "", bruto_gudang: "" });

        setMode("TARA_GUDANG");

        await syncStatus(truckId);
        await fetchData(truckId);
      }
    } catch (err) {
      console.error("SUBMIT ERROR:", err);
      alert(err.response?.data?.message || "Gagal proses timbang gudang");
    } finally {
      setSubmitting(false);
    }
  };

  // ================= UI =================
  return (
    <div className="p-8 min-h-screen bg-gradient-to-br from-green-100 to-white">

      <h1 className="text-3xl font-bold text-center mb-6">
        ⚖️ Timbang Gudang System
      </h1>

      <p className="text-center mb-4 font-semibold">
        Mode:{" "}
        {mode === "TARA_GUDANG"
          ? "INPUT TARA GUDANG"
          : "INPUT BRUTO GUDANG"}
      </p>

      {loading && (
        <div className="flex justify-center">
          <div className="animate-spin w-14 h-14 border-4 border-green-500 border-t-transparent rounded-full"></div>
        </div>
      )}

      {!truck && !loading && (
        <p className="text-center text-gray-600">
          Menunggu RFID scan...
        </p>
      )}

      {truck && (
        <div className="max-w-5xl mx-auto bg-white p-6 shadow rounded">

          {/* INFO TRUCK */}
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div><b>Truck ID:</b> {truck.truckId}</div>
            <div><b>Driver:</b> {truck.driver}</div>
            <div><b>Tipe:</b> {truck.truckType}</div>
            <div><b>Tanggal:</b> {truck.date?.split("T")[0]}</div>
          </div>

          {/* FORM */}
          <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">

            {mode === "TARA_GUDANG" ? (
              <input
                type="number"
                name="tara_gudang"
                placeholder="Tara Gudang"
                value={form.tara_gudang}
                onChange={handleChange}
                className="border p-2 rounded"
              />
            ) : (
              <input
                type="number"
                name="bruto_gudang"
                placeholder="Bruto Gudang"
                value={form.bruto_gudang}
                onChange={handleChange}
                className="border p-2 rounded"
              />
            )}

            <div className="col-span-2 flex justify-end gap-3 mt-3">
              <button
                type="button"
                onClick={() => navigate(-1)}
                className="bg-gray-400 px-4 py-2 rounded text-white"
              >
                Kembali
              </button>

              <button
                disabled={submitting}
                className="bg-green-600 px-4 py-2 rounded text-white"
              >
                {submitting ? "Proses..." : "Simpan"}
              </button>
            </div>

          </form>

          {/* TABLE */}
          <div className="mt-10">
            <h2 className="font-bold mb-3">
              Riwayat Timbang Gudang
            </h2>

            <div className="overflow-x-auto">
              <table className="w-full border text-sm">
                <thead className="bg-green-200">
                  <tr>
                    <th className="border p-2">Item</th>
                    <th className="border p-2">Tara Gudang</th>
                    <th className="border p-2">Bruto Gudang</th>
                    <th className="border p-2">Netto Gudang</th>
                    <th className="border p-2">Status</th>
                  </tr>
                </thead>

                <tbody>
                  {list.length > 0 ? (
                    list.map((item) => (
                      <tr key={item.id}>
                        <td className="border p-2">
                          {item.itemType}
                        </td>
                        <td className="border p-2">
                          {item.tara_gudang ?? 0}
                        </td>
                        <td className="border p-2">
                          {item.bruto_gudang ?? 0}
                        </td>
                        <td className="border p-2 font-bold">
                          {item.netto_gudang ?? 0}
                        </td>
                        <td className="border p-2">
                          {item.status_timbang}
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="5" className="text-center p-4">
                        Belum ada data gudang
                      </td>
                    </tr>
                  )}
                </tbody>

              </table>
            </div>
          </div>

        </div>
      )}
    </div>
  );
};

export default TimbangGudang;
